func (o *Event) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "Confirmations":
		rels, ok := retrieved.(ConfirmationSlice)
		if !ok {
			return fmt.Errorf("event cannot load %T as %q", retrieved, name)
		}

		o.R.Confirmations = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Event = o
			}
		}
		return nil
	case "Facilities":
		rels, ok := retrieved.(FacilitySlice)
		if !ok {
			return fmt.Errorf("event cannot load %T as %q", retrieved, name)
		}

		o.R.Facilities = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Events = EventSlice{o}
			}
		}
		return nil
	case "EventTimeSlots":
		rels, ok := retrieved.(EventTimeSlotSlice)
		if !ok {
			return fmt.Errorf("event cannot load %T as %q", retrieved, name)
		}

		o.R.EventTimeSlots = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Event = o
			}
		}
		return nil
	case "JoinRequests":
		rels, ok := retrieved.(JoinRequestSlice)
		if !ok {
			return fmt.Errorf("event cannot load %T as %q", retrieved, name)
		}

		o.R.JoinRequests = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Event = o
			}
		}
		return nil
	default:
		return fmt.Errorf("event has no relationship %q", name)
	}
}

