// LoadEventFacilities loads the event's Facilities into the .R struct
func (os EventSlice) LoadEventFacilities(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	// since we are changing the columns, we need to check if the original columns were set or add the defaults
	sq := dialect.SelectQuery{}
	for _, mod := range mods {
		mod.Apply(&sq)
	}

	if len(sq.SelectList.Columns) == 0 {
		mods = append(mods, sm.Columns(Facilities.Columns()))
	}

	q := os.Facilities(append(
		mods,
		sm.Columns(EventLocationColumns.EventID.As("related_events.ID")),
	)...)

	IDSlice := []string{}

	mapper := scan.Mod(scan.StructMapper[*Facility](), func(ctx context.Context, cols []string) (scan.BeforeFunc, func(any, any) error) {
		return func(row *scan.Row) (any, error) {
				IDSlice = append(IDSlice, *new(string))
				row.ScheduleScan("related_events.ID", &IDSlice[len(IDSlice)-1])

				return nil, nil
			},
			func(any, any) error {
				return nil
			}
	})

	facilities, err := bob.Allx[*Facility, FacilitySlice](ctx, exec, q, mapper)
	if err != nil {
		return err
	}

	for _, o := range os {
		o.R.Facilities = nil
	}

	for _, o := range os {
		for i, rel := range facilities {
			if o.ID != IDSlice[i] {
				continue
			}

			rel.R.Events = append(rel.R.Events, o)

			o.R.Facilities = append(o.R.Facilities, rel)
		}
	}

	return nil
}

